/* BATCH 13: Monitoring Advanced */
static void cmd_htop(int argc, char args[][CMD_MAX_LEN]) {
    vga_clear();
    char buf[32];
    unsigned int total = pmm_get_total_pages() * 4;
    unsigned int free_p = pmm_get_free_pages() * 4;
    unsigned int used = total - free_p;
    vga_set_color(VGA_LIGHT_CYAN, VGA_BLACK);
    vga_puts("BYO-OS System Monitor");
    vga_puts("  |  ");
    vga_puts("Mem: ");
    itoa(used / 1024, buf, 10); vga_puts(buf); vga_puts("M/");
    itoa(total / 1024, buf, 10); vga_puts(buf); vga_puts("M");
    vga_puts("  |  Tasks: ");
    itoa(task_get_count(), buf, 10); vga_puts(buf);
    vga_puts("\n");
    vga_puts("  PID  STAT  CPU  MEM    NAME\n");
    vga_puts("  ---- ----  ---  -----  --------------------\n");
    vga_set_color(VGA_LIGHT_GREY, VGA_BLACK);
    int max = task_get_max_tasks();
    for (int i = 0; i < max; i++) {
        if (task_is_active(i)) {
            char buf[16]; itoa(i, buf, 10);
            for (int p = strlen(buf); p < 5; p++) vga_putchar(' ');
            vga_puts(buf); vga_puts("  ");
            vga_puts(task_get_state_name(i)); vga_puts("  ");
            vga_puts(task_get_name_by_pid(i)); vga_putchar('\n');
        }
    }
    char buf2[16];
    vga_puts("\nFree: "); itoa(pmm_get_free_pages(), buf2, 10); vga_puts(buf2); vga_puts(" pages  ");
    vga_puts("Tasks: "); itoa(task_get_count(), buf2, 10); vga_puts(buf2); vga_putchar('\n');
}

