/* 64-bit division helper (avoids __divdi3) */
static long long b115_div64(long long a, long long b) {
    if (b == 0) return 0;
    int neg = 0;
    if (a < 0) { a = -a; neg ^= 1; }
    if (b < 0) { b = -b; neg ^= 1; }
    long long q = 0, r = 0;
    for (int i = 63; i >= 0; i--) {
        r = (r << 1) | ((a >> i) & 1);
        if (r >= b) { r -= b; q |= (1LL << i); }
    }
    return neg ? -q : q;
}

