void shell_run(void) {
    vga_clear();
    vga_set_color(VGA_LIGHT_GREEN, VGA_BLACK);
    vga_puts("Welcome to BYO-OS Shell v1.0\n");
    vga_puts("Type 'help' for available commands.\n\n");
    input_len = 0;
    input_buf[0] = 0;
    serial_cmd_len = 0;
    serial_collecting = 0;
    print_prompt();

    while (1) {
        net_poll();
        sig_process45();
        cron_tick45();
        bg_check45();

        /* === Handle serial input (non-blocking) === */
        if (serial_has_input()) {
            char sc = serial_getchar();
            if (sc == 10 || sc == 13) {
                serial_cmd_buf[serial_cmd_len] = 0;
                if (serial_cmd_len > 0) {
                    vga_set_serial_mode(1);
                    shell_execute(serial_cmd_buf);
                    vga_set_serial_mode(0);
                }
                serial_cmd_len = 0;
                serial_collecting = 0;
                serial_puts("BYO-OS>\n");
            } else if (sc == 8 && serial_cmd_len > 0) {
                serial_cmd_len--;
            } else if (serial_cmd_len < CMD_MAX_LEN - 1) {
                serial_cmd_buf[serial_cmd_len++] = sc;
                serial_collecting = 1;
            }
            if (serial_has_input()) continue;
        }

        /* === Handle keyboard input (non-blocking) === */
        int kc = keyboard_getchar();
        if (kc == -1) {
            for (volatile int d = 0; d < 2000; d++) {}
            continue;
        }
        char c = (char)kc;

        if (c == 13 || c == 10) {
            input_buf[input_len] = 0;
            vga_putchar('\n');
            if (input_len > 0) shell_execute(input_buf);
            input_len = 0;
            input_buf[0] = 0;
            print_prompt();
        } else if (c == 8) {
            if (input_len > 0) {
                input_len--;
                input_buf[input_len] = 0;
                vga_putchar('\b'); vga_putchar(' '); vga_putchar('\b');
            }
        } else if (c >= 32 && c <= 126) {
            if (input_len < CMD_MAX_LEN - 1) {
                input_buf[input_len++] = c;
                input_buf[input_len] = 0;
                vga_putchar(c);
            }
        }
    }
}

static void cmd_type44(int argc, char args[][CMD_MAX_LEN]) {
    if(argc<2){vga_puts("Usage: type <command>\n");return;}
    for(int i=1;i<argc;i++){int found=0;
    for(int j=0;commands[j].name;j++){if(strcmp(args[i],commands[j].name)==0){vga_puts(args[i]);vga_puts(" is /usr/bin/");vga_puts(args[i]);vga_putchar('\n');found=1;break;}}
    if(!found){vga_puts(args[i]);vga_puts(": not found\n");}}
}
static void cmd_watch44(int argc, char args[][CMD_MAX_LEN]) {
    if(argc<2){vga_puts("Usage: watch <command>\n");return;}
    for(int n=0;n<3;n++){vga_puts("--- Run ");char buf[8];itoa(n+1,buf,10);vga_puts(buf);vga_puts(" ---\n");
    for(int i=0;commands[i].name;i++){if(strcmp(args[1],commands[i].name)==0){commands[i].func(argc-1,&args[1]);break;}}timer_sleep(2000);}
}
static void cmd_time44(int argc, char args[][CMD_MAX_LEN]) {
    if(argc<2){vga_puts("Usage: time <command>\n");return;}
    uint32_t start=timer_get_ticks();
    for(int i=0;commands[i].name;i++){if(strcmp(args[1],commands[i].name)==0){commands[i].func(argc-1,&args[1]);break;}}
    uint32_t elapsed=timer_get_ticks()-start;char buf[32];vga_puts("real\t");itoa(elapsed/100,buf,10);vga_puts(buf);vga_puts(".");itoa(elapsed%100,buf,10);vga_puts(buf);vga_puts("s\n");
}



static void cron_tick45(void) {
    if (!cron_enabled45) return;
    uint32_t sec = timer_get_seconds();
    int minute = (sec / 60) % 60;
    for (int i = 0; i < cron_count45; i++) {
        if (!cron_jobs45[i].active) continue;
        if (cron_jobs45[i].minute == -1 || cron_jobs45[i].minute == minute) {
            for (int j = 0; commands[j].name; j++) {
                if (strcmp(cron_jobs45[i].cmd, commands[j].name) == 0) { commands[j].func(0, 0); break; }
            }
        }
    }
}
